package com.example.pricing_calculation.web;
import com.example.pricing_calculation.domain.*;import com.example.pricing_calculation.dto.IncidentDtos.*;import com.example.pricing_calculation.service.*;import io.swagger.v3.oas.annotations.security.SecurityRequirement;import io.swagger.v3.oas.annotations.tags.Tag;import java.util.List;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/staff/incidents") @SecurityRequirement(name="bearerAuth") @Tag(name="Parking Staff Incidents",description="Mat ve, sai bien so, qua gio, sai khu vuc va chua thanh toan") public class UnifiedIncidentController {private final PaymentModuleAuthService auth;private final UnifiedIncidentService service;public UnifiedIncidentController(PaymentModuleAuthService auth,UnifiedIncidentService service){this.auth=auth;this.service=service;}private UserAccount staff(String h){return auth.requireAnyRole(h,UserRole.PARKING_STAFF,UserRole.PARKING_MANAGER,UserRole.ADMINISTRATOR);}@GetMapping public List<IncidentResponse>list(@RequestHeader("Authorization")String h,@RequestParam(required=false)String status){staff(h);return service.list(status);}@PostMapping public IncidentResponse create(@RequestHeader("Authorization")String h,@RequestBody IncidentRequest r){return service.create(staff(h),r);}@PatchMapping("/{id}/resolve")public IncidentResponse resolve(@RequestHeader("Authorization")String h,@PathVariable Long id){return service.resolve(staff(h),id);}}
